1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty grid when given empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single cell with no neighbors (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent cells each having only one neighbor (underpopulation)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a block pattern alive where each cell has exactly 3 neighbors (survival)", () => {
15	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const result = nextGeneration(block);
17	    expect(result.sort()).toEqual([[0, 0], [0, 1], [1, 0], [1, 1]]);
18	  });
19	  it("should kill a live cell with more than 3 neighbors (overpopulation)", () => {
20	    const plus: [number, number][] = [[1, 0], [0, 1], [1, 1], [2, 1], [1, 2]];
21	    const result = nextGeneration(plus);
22	    expect(result).not.toContainEqual([1, 1]);
23	  });
24	  it.todo("should bring a dead cell to life when it has exactly 3 live neighbors (reproduction)");
25	  it.todo("should evolve a blinker from vertical to horizontal (oscillator)");
26	});
27

1	export type Cell = [number, number];
2	
3	const isNeighbor = ([x1, y1]: Cell, [x2, y2]: Cell): boolean => {
4	  const dx = Math.abs(x1 - x2);
5	  const dy = Math.abs(y1 - y2);
6	  return dx <= 1 && dy <= 1 && dx + dy > 0;
7	};
8	
9	const countNeighbors = (cell: Cell, liveCells: Cell[]): number =>
10	  liveCells.filter((other) => isNeighbor(cell, other)).length;
11	
12	export const nextGeneration = (liveCells: Cell[]): Cell[] =>
13	  liveCells.filter((cell) => {
14	    const neighbors = countNeighbors(cell, liveCells);
15	    return neighbors === 2 || neighbors === 3;
16	  });
