it("should bring a dead cell to life when it has exactly 3 live neighbors (reproduction)", () => {
  const liveCells: [number, number][] = [[0, 0], [1, 0], [0, 1]];
  const result = nextGeneration(liveCells);
  expect(result).toContainEqual([1, 1]);
});
